FormulationListener = {}

function FormulationListener:init()
    FormulationSubmitEvent.registerCallBack(self.onComposeMaterial)
end

function FormulationListener.onComposeMaterial(rakssId, id, count)
    local player = PlayerManager:getPlayerByRakssid(rakssId)
    local formulation = FormulationConfig:getFormulationById(id)
    if not player or not formulation then
        return
    end
    --material enough?
    --HostApi.broadCastMsgByType(rakssId, 5, 3, 116,  "tttt")

    for _, materialId in pairs(formulation.MaterialsId) do
        local material = MaterialConfig:getMaterialById(tonumber(materialId))
        if not material then
            return
        end
        local num = player:getItemNumById(material.ItemId)
        --print(material.ItemId, num)
        if num < material.Count * count then
            --material not enough
            HostApi.sendCommonTip(player.rakssid, "walkingDead.formulation.no.enough.material")
            return
        end
    end

    --remove material
    for _, materialId in pairs(formulation.MaterialsId) do
        local material = MaterialConfig:getMaterialById(tonumber(materialId))
        if not material then
            return
        end
        player:removeItem(material.ItemId, material.Count * count)
        --local num = player:getItemNumById(material.ItemId)
    end
    player:addItem(formulation.ItemId, formulation.Count * count, 0, false)
    HostApi.notifyGetItem(rakssId,formulation.ItemId,0,formulation.Count * count)
end

return FormulationListener


